--
-- Table structure for table `carpeta`
--

DROP TABLE IF EXISTS `carpeta`;
SET @saved_cs_client     = @@character_set_client;
SET character_set_client = utf8;
CREATE TABLE `carpeta` (
  `idCarpeta` int(11) NOT NULL default '0' COMMENT 'Identificador primario de la carpeta',
  `FxAlta` datetime default NULL COMMENT 'Fecha de creacion de la carpeta',
  `FxMod` datetime default NULL COMMENT 'Fecha de modificacion de la carpeta',
  `FxEmision` date default NULL COMMENT 'Fecha de emision de la carpeta',
  `TrAduanero` tinyint(1) default '0' COMMENT 'Decribe si es transito aduanero o no',
  `LcPartida` int(11) default '0' COMMENT 'Ciudad , pais de partida',
  `AdOrigen` int(11) default '0' COMMENT 'Aduana de origen',
  `LcDestino` int(11) default '0' COMMENT 'Ciudad , pais de destino',
  `AdDestino` int(11) default '0' COMMENT 'Aduana de destino',
  `CmOriginal` int(11) default '0' COMMENT 'Camion original',
  `RsOriginal` int(11) default '0' COMMENT 'Chofer  Original',
  `SemiRemolqueOrig` int(11) default '0',
  `CmSubstituto` int(11) default '0' COMMENT 'Camion subtituto',
  `RsSubstituto` int(11) default '0' COMMENT 'Chofer substituto',
  `SemiRemolqueSubstituto` int(11) default '0' COMMENT 'Semiremolque substituto.',
  `EmRemitente` int(11) default '0' COMMENT 'Empresa remitente',
  `EmConsignataria` int(11) default '0' COMMENT 'Empresa consignataria',
  `EmDestinataria` int(11) default '0' COMMENT 'Empresa destinataria',
  `EmNotificar` int(11) default '0' COMMENT 'Empresa a notificar',
  `LcEmision` int(11) default '0' COMMENT 'Localidad  de emision',
  `LcPortadorCargo` int(11) default '0' COMMENT 'Pais en que el portador se hace cargo',
  `LcEntrega` int(11) default '0' COMMENT 'Donde se hace la entrega',
  `NmPrecinto` varchar(50) character set utf8 default NULL COMMENT 'Numero de precinto del contenedor',
  `LcOrigenMercaderia` int(11) default '0' COMMENT 'Origen de la mercaderia',
  `Moneda` varchar(50) character set utf8 default NULL COMMENT 'Moneda',
  `ValorFOT` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Valor FOT',
  `ValorMercaderias` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Valor de las mercaderias',
  `CostoFlete` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Costo del flete',
  `Seguro` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Seguro',
  `Volumen` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'En metros cubicos',
  `CantidadDeBultos` varchar(50) character set utf8 default NULL COMMENT 'Canitidad de bultos del contenedor',
  `Bulto` int(11) default '0' COMMENT 'Tipo de bulto que contiene',
  `PesoBruto` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Peso en bruto',
  `Gastos` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Gastos',
  `MontoRemitente` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Monto del remitente',
  `MnRemitente` varchar(50) character set utf8 default NULL COMMENT 'Moneda que usa el remitente',
  `MontoDestinatario` varchar(50) collate utf8_unicode_ci default NULL COMMENT 'Monto del destinatario',
  `MnDestinatario` varchar(50) character set utf8 default NULL COMMENT 'Moneda que utiliza el destinatario',
  `MontoFleteExterno` varchar(50) collate utf8_unicode_ci default NULL,
  `MontoRemobolso` varchar(50) collate utf8_unicode_ci default NULL,
  `Otros` varchar(50) character set utf8 default NULL,
  `MarcaNumeroBultos` varchar(3000) character set utf8 default NULL,
  `DocAnexos` varchar(1100) character set utf8 default NULL,
  `FormalidadesAduana` varchar(1100) character set utf8 default NULL,
  `idRuta` int(11) default '0',
  `transportadora` int(11) default NULL,
  `historico` tinyint(1) default '0' COMMENT 'Indica si es de historico o no, 1 es de historico 0 no lo es.',
  `nroDocumento` int(11) default NULL COMMENT 'nro de CRT o documento',
  `cantidadMic` int(3) default NULL COMMENT 'la cantidad de documentos mic/dta relacionados con la carpeta',
  `nombreBuque` varchar(25) collate utf8_unicode_ci default NULL COMMENT 'El nombre del buque que llego al puerto',
  `fechaLlegadaBuque` date default NULL COMMENT 'fecha en la que llego el buque al puerto',
  `nroContenedor` char(13) collate utf8_unicode_ci default '' COMMENT 'numero del contenedor  4 letras  -  6 digitios -  un digito',
