  `Nombre` char(50) NOT NULL COMMENT 'Nombre del responsable del vehiculo',
  `Apellido` char(50) NOT NULL COMMENT 'Apellido de responsable del vehiculo',
  `Documento` char(50) NOT NULL COMMENT 'Documento',
  `FK_Localidad` int(11) default NULL,
  `Activo` smallint(6) default '1' COMMENT '1 Esta Activo 0 Esta Borrado',
  `telefono` varchar(50) default NULL,
  PRIMARY KEY  (`CodResponsable`)
) ENGINE=InnoDB AUTO_INCREMENT=442 DEFAULT CHARSET=utf8;
SET character_set_client = @saved_cs_client;

