/*!50003 DROP PROCEDURE IF EXISTS `sp_numeradores` */;;
/*!50003 SET SESSION SQL_MODE=""*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `sp_numeradores`(IN codTransportadora INTEGER, IN cantidadMic INTEGER)
BEGIN
 
declare x INT default 0;
declare padre INT default 0;
declare numeroMIC INT default 0;
declare esCRTAux INT default 0;

	select ifnull(idcarpeta,0) from numerador_carpeta into @idCarpeta;
	select numero  from numeradores
	where  codTransportadora= numeradores.`CodTransportadora` into @numDocumento;


Update numeradores set numero = @numDocumento+cantidadMic where codTransportadora = numeradores.`CodTransportadora`;
Update numerador_carpeta set idcarpeta = @idCarpeta+cantidadMic;


select transportadora.prefijo from transportadora where codTransportadora= transportadora.`CodTransportadora` into  @prefijo;

set @idCarpeta = @idCarpeta+1;
select concat(@prefijo,@numDocumento+1) as numDocumento, @idCarpeta as idCarpeta;

set padre = @idCarpeta;
set numeroMIC = @numDocumento; 
WHILE x  < cantidadMic DO

IF (x = 0) THEN
	set @numDocumento = @numDocumento+1; 
	set numeroMIC = numeroMIC+1;
  	set esCRTAux = 1; 
END IF;
	 
IF (x > 0) THEN
  		set esCRTAux = 0; 
END IF;

insert into  `carpeta`(idCarpeta,idCarpetaPadre,fxAlta,transportadora,nroDocumento,cantidadMic,transportadoraCamionSustituto,esCRT,nroMIC,FormalidadesAduana,DocAnexos,nombreFirmaDestinatario,TrAduanero) values(@idCarpeta,padre,now(),codTransportadora,@numDocumento,cantidadMic,0,esCRTAux,numeroMIC,'PESO - CALIDAD Y CONTENIDO DECLARADO POR EL EMBARCADOR SIN CONTROL DEL TRANSPORTISTA','NUMERO DE FACTURA:','SEGURO DE LA MERCADERIA POR CUENTA Y ORDEN DEL IMPORTADOR SIN PERJUICIO NI REPETICION PARA LA EMPRESA TRANSPORTADORA',true);  

set numeroMIC = numeroMIC+1;
set @idCarpeta = @idCarpeta+1;

SET  x = x + 1; 
END WHILE;

COMMIT;
END */;;
