/*!50003 DROP PROCEDURE IF EXISTS `sp_pasar_historico` */;;
/*!50003 SET SESSION SQL_MODE=""*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `sp_pasar_historico`(IN idCarp INTEGER,IN carpetaPadre INTEGER,IN fechaPasado DATETIME,IN fechaAlta DATETIME,IN fechaModificacion DATETIME,IN xml VARCHAR(20000),IN numeroContenedor VARCHAR(255))
BEGIN

INSERT INTO  `historicos` VALUES(idCarp,carpetaPadre,fechaPasado,fechaAlta,fechaModificacion,xml,numeroContenedor);
DELETE FROM `carpeta`  where idCarpeta=idCarp;
COMMIT;

END */;;
